final class PromoManager: ObservableObject {
    static let shared = PromoManager()

    @Published private(set) var userAccount: UserAccount
    @Published private(set) var lastHandledURL: URL?
    @Published private(set) var lastStatusMessage: String = "Waiting for a promo link…"
    @Published private(set) var lastStatusIsError: Bool = false

    private init() {
        self.userAccount = UserAccountStore.shared.load() ?? UserAccount(userId: UserAccountStore.shared.getOrCreateUserId())
    }

    @discardableResult
    func handleIncomingURL(_ url: URL) -> Bool {
        lastHandledURL = url

        guard let promo = PromoLinkParser.parse(url: url) else {
            setStatus("Invalid promo link.", isError: true)
            return false
        }

        applyPromoToUserAccount(promo)
        return true
    }

    func resetPromo() {
        userAccount.appliedPromoCode = nil
        userAccount.appliedDiscountPercent = nil
        userAccount.appliedAt = nil
        UserAccountStore.shared.save(userAccount)
        setStatus("Promo cleared.", isError: false)
    }

    private func applyPromoToUserAccount(_ promo: PromoData) {
        userAccount.appliedPromoCode = promo.code
        userAccount.appliedDiscountPercent = promo.discountPercent
        userAccount.appliedAt = Date()
        UserAccountStore.shared.save(userAccount)
        setStatus("Applied promo \(promo.code) for \(promo.discountPercent)% off.", isError: false)
    }

    private func setStatus(_ message: String, isError: Bool) {
        lastStatusMessage = message
        lastStatusIsError = isError
    }
}

struct PromoData: Equatable, Codable {
    let code: String
    let discountPercent: Int
}

enum PromoLinkParser {
    static func parse(url: URL) -> PromoData? {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: false) else { return nil }

        guard let host = components.host?.lowercased(),
              host == "myapp.com" else { return nil }

        let path = components.path.lowercased()
        guard path == "/promo" || path == "/promo/" else { return nil }

        let items = components.queryItems ?? []
        let dict = Dictionary(uniqueKeysWithValues: items.compactMap { item in
            guard let value = item.value else { return nil }
            return (item.name.lowercased(), value)
        })

        guard let codeRaw = dict["code"]?.trimmingCharacters(in: .whitespacesAndNewlines),
              !codeRaw.isEmpty else { return nil }

        guard let discountRaw = dict["discount"]?.trimmingCharacters(in: .whitespacesAndNewlines),
              let discount = Int(discountRaw) else { return nil }

        guard (0...100).contains(discount) else { return nil }

        let sanitizedCode = sanitizePromoCode(codeRaw)
        guard !sanitizedCode.isEmpty else { return nil }

        return PromoData(code: sanitizedCode, discountPercent: discount)
    }

    private static func sanitizePromoCode(_ input: String) -> String {
        let allowed = CharacterSet.alphanumerics.union(CharacterSet(charactersIn: "-_"))
        let filteredScalars = input.unicodeScalars.filter { allowed.contains($0) }
        return String(String.UnicodeScalarView(filteredScalars)).uppercased()
    }
}

struct UserAccount: Codable {
    var userId: String
    var appliedPromoCode: String?
    var appliedDiscountPercent: Int?
    var appliedAt: Date?
}

final class UserAccountStore {
    static let shared = UserAccountStore()

    private let accountKey = "UserAccountStore.account"
    private let userIdKey = "UserAccountStore.userId"
    private let defaults = UserDefaults.standard
    private let encoder = JSONEncoder()
    private let decoder = JSONDecoder()

    private init() {
        encoder.dateEncodingStrategy = .iso8601
        decoder.dateDecodingStrategy = .iso8601
    }

    func getOrCreateUserId() -> String {
        if let id = defaults.string(forKey: userIdKey), !id.isEmpty {
            return id
        }
        let id = UUID().uuidString
        defaults.set(id, forKey: userIdKey)
        return id
    }

    func load() -> UserAccount? {
        guard let data = defaults.data(forKey: accountKey) else { return nil }
        return try? decoder.decode(UserAccount.self, from: data)
    }

    func save(_ account: UserAccount) {
        if let data = try? encoder.encode(account) {
            defaults.set(data, forKey: accountKey)
        }
    }
}

